import { useState } from "react";

export default function ForgotPasswordPage({ setPage }) {
  const [step, setStep] = useState(1); // 1=email, 2=otp, 3=reset, 4=success
  const [email, setEmail] = useState("");
  const [otp, setOtp] = useState(["", "", "", "", "", ""]);
  const [newPass, setNewPass] = useState("");
  const [confirmPass, setConfirmPass] = useState("");
  const [showNew, setShowNew] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);

  const handleOtpChange = (i, val) => {
    if (!/^\d?$/.test(val)) return;
    const next = [...otp];
    next[i] = val;
    setOtp(next);
    if (val && i < 5) document.getElementById(`otp-${i+1}`)?.focus();
  };

  const stepImages = [
    "https://images.unsplash.com/photo-1498837167922-ddd27525d352?w=700&h=1000&fit=crop",
    "https://images.unsplash.com/photo-1498837167922-ddd27525d352?w=700&h=1000&fit=crop",
    "https://images.unsplash.com/photo-1498837167922-ddd27525d352?w=700&h=1000&fit=crop",
  ];

  return (
    <div className="auth-split">
      <div className="auth-visual">
        <img src="https://images.unsplash.com/photo-1498837167922-ddd27525d352?w=700&h=1000&fit=crop" alt="food" />
        <div className="auth-visual-overlay" />
        <div className="auth-visual-text">
          <h2>Reset your password</h2>
          <p>We'll help you get back to cooking in no time.</p>
        </div>
      </div>

      <div className="auth-panel">
        <div className="auth-logo">
          <div className="auth-logo-icon">🍽</div>
          <span className="auth-logo-text">RecipeNest</span>
        </div>

        {/* STEP 1 — Email */}
        {step === 1 && (<>
          <h1 className="auth-heading">Forgot Password?</h1>
          <p className="auth-subheading">Enter your email and we'll send you a verification code.</p>
          <label className="field-label">Email Address</label>
          <div className="field-wrap">
            <span className="field-icon">✉</span>
            <input className="field-input" type="email" placeholder="name@company.com"
              value={email} onChange={e => setEmail(e.target.value)} />
          </div>
          <button className="btn-primary" onClick={() => setStep(2)}>Send Reset Code</button>
          <div className="auth-footer"><button onClick={() => setPage("login")}>← Back to Login</button></div>
        </>)}

        {/* STEP 2 — OTP */}
        {step === 2 && (<>
          <h1 className="auth-heading">Check your email</h1>
          <p className="auth-subheading">We sent a 6-digit code to <strong style={{color:"#333"}}>{email || "your email"}</strong>. Enter it below.</p>
          <div style={{ display:"flex", gap:8, justifyContent:"center", margin:"8px 0 24px" }}>
            {otp.map((d, i) => (
              <input key={i} id={`otp-${i}`}
                style={{ width:46, height:52, textAlign:"center", fontSize:20, fontWeight:700, border:"1.5px solid #e0ddd8", borderRadius:9, outline:"none", background:"#fafaf8", color:"#222", transition:"border-color .18s" }}
                maxLength={1} value={d}
                onChange={e => handleOtpChange(i, e.target.value)}
                onFocus={e => e.target.style.borderColor = "#e85d2f"}
                onBlur={e => e.target.style.borderColor = "#e0ddd8"}
              />
            ))}
          </div>
          <button className="btn-primary" onClick={() => setStep(3)}>Verify Code</button>
          <div style={{textAlign:"center", fontSize:13, color:"#888", marginTop:16}}>
            Didn't receive it? <button className="btn-ghost">Resend code</button>
          </div>
          <div className="auth-footer"><button onClick={() => setPage("login")}>← Back to Login</button></div>
        </>)}

        {/* STEP 3 — New password */}
        {step === 3 && (<>
          <h1 className="auth-heading">Set New Password</h1>
          <p className="auth-subheading">Choose a strong password for your account.</p>
          <label className="field-label">New Password</label>
          <div className="field-wrap">
            <span className="field-icon">🔒</span>
            <input className="field-input" type={showNew ? "text" : "password"} placeholder="••••••••"
              value={newPass} onChange={e => setNewPass(e.target.value)} />
            <button className="field-eye" onClick={() => setShowNew(v => !v)}>{showNew ? "🙈" : "👁"}</button>
          </div>
          {/* Password strength bar */}
          {newPass && (
            <div style={{ marginTop:-8, marginBottom:16 }}>
              <div style={{ height:4, borderRadius:2, background:"#f0ede6", overflow:"hidden" }}>
                <div style={{ height:"100%", width: newPass.length > 10 ? "100%" : newPass.length > 6 ? "60%" : "30%",
                  background: newPass.length > 10 ? "#3aab5e" : newPass.length > 6 ? "#e8b82f" : "#e85d2f",
                  transition:"width .3s, background .3s" }} />
              </div>
              <span style={{ fontSize:11, color: newPass.length > 10 ? "#3aab5e" : newPass.length > 6 ? "#a07800" : "#e85d2f" }}>
                {newPass.length > 10 ? "Strong" : newPass.length > 6 ? "Medium" : "Weak"}
              </span>
            </div>
          )}
          <label className="field-label">Confirm Password</label>
          <div className="field-wrap">
            <span className="field-icon">🔒</span>
            <input className="field-input" type={showConfirm ? "text" : "password"} placeholder="••••••••"
              value={confirmPass} onChange={e => setConfirmPass(e.target.value)} />
            <button className="field-eye" onClick={() => setShowConfirm(v => !v)}>{showConfirm ? "🙈" : "👁"}</button>
          </div>
          <button className="btn-primary" onClick={() => setStep(4)}>Reset Password</button>
        </>)}

        {/* STEP 4 — Success */}
        {step === 4 && (
          <div style={{ textAlign:"center", padding:"20px 0" }}>
            <div style={{ width:72, height:72, borderRadius:"50%", background:"#f0faf4", border:"2px solid #3aab5e", display:"flex", alignItems:"center", justifyContent:"center", fontSize:32, margin:"0 auto 24px" }}>✅</div>
            <h1 className="auth-heading" style={{ textAlign:"center" }}>Password Reset!</h1>
            <p style={{ fontSize:14, color:"#888", marginTop:8, marginBottom:32, lineHeight:1.6 }}>
              Your password has been updated successfully. You can now sign in with your new password.
            </p>
            <button className="btn-primary" onClick={() => setPage("login")}>Back to Login</button>
          </div>
        )}
      </div>
    </div>
  );
}
